// Extract wallet addresses from leaderboard entries
const leaders = $input.all();
const wallets = leaders.map(item => ({
  json: {
    walletAddress: item.json.walletAddress || item.json.address || item.json.wallet,
    userName: item.json.userName || item.json.username || item.json.name || 'Unknown',
    rank: item.json.rank || 0,
    profit: item.json.profit || item.json.pnl || 0
  }
}));

return wallets.filter(w => w.json.walletAddress);

// Filter trades from the last 30 minutes and format whale alerts
const trades = $input.all();
const thirtyMinAgo = Date.now() - (30 * 60 * 1000);
const alerts = [];

for (const item of trades) {
  const t = item.json;
  const tradeTime = new Date(t.timestamp || t.createdAt || 0).getTime();

  if (tradeTime > thirtyMinAgo) {
    const side = (t.side || t.type || 'UNKNOWN').toUpperCase();
    const price = Number(t.price || 0).toFixed(2);
    const size = Number(t.size || t.amount || 0).toFixed(2);
    const market = t.market || t.question || t.conditionId || 'Unknown market';
    const userName = t.userName || 'Whale';

    alerts.push({
      json: {
        message: `Whale ${userName} just ${side === 'BUY' ? 'bought' : 'sold'} ${market} -- ${size} shares at $${price}`,
        side,
        price,
        size,
        market,
        userName,
        timestamp: t.timestamp || t.createdAt
      }
    });
  }
}

// If no recent trades, return empty to skip Telegram
if (alerts.length === 0) {
  return [{ json: { _skip: true } }];
}

return alerts;
